            reason,
            pausedAt,
            resumedAt,
            pauseDurationSeconds: Math.max(0, Number(entry?.pauseDurationSeconds || 0)),
          };
        }
        if (resumedAt) {
          return {
            reason,
            pausedAt,
            resumedAt,
            pauseDurationSeconds: Math.max(0, Number(entry?.pauseDurationSeconds || 0)),
          };
        }
