    const key = mapa[diaId];
    const inicio = config[`horario_${key}_inicio`] || config.horario_inicio || "08:00";
    const fin = config[`horario_${key}_fin`] || config.horario_fin || "22:00";
    const [hi, mi] = inicio.split(":").map(Number);
