        }),
      });
      setMensajesDestacados((prev) => {
        const next = new Set(Array.from(prev).map(String));
        if (res?.destacado) {
          next.add(String(mensaje.id));
        } else {
          next.delete(String(mensaje.id));
        }
        return next;
      });
