        socket.off("connect", onConnect);
        socket.off("connect_error", onConnectError);
        clearTimeout(timer);
      };
      const onConnect = () => {
        if (settled) return;
        settled = true;
        cleanup();
        resolve(true);
      };
      const onConnectError = () => {
        // Esperar al timeout: Socket.IO puede recuperarse solo.
      };
      const timer = setTimeout(() => {
        if (settled) return;
        settled = true;
        cleanup();
        resolve(false);
      }, timeoutMs);

      socket.on("connect", onConnect);
