                        return gruposOrdenados.map((nombreGrupo) => {
                          const gruposEnGrupo = agrupados[nombreGrupo];
                          const tieneNoLeidos = tieneNoLeidosEnGrupo(gruposEnGrupo, false);
                          const estaColapsado = gruposGruposCollapsed[nombreGrupo] || false;
                          
