                                            <button
                                              key={carpeta}
                                              onClick={() => asignarACarpeta(g.id, 'grupo', carpeta)}
                                            >
                                              ­ƒôü {carpeta}
                                            </button>
                                          ))}
                                        </div>
                                      </div>
                                    )}
                                  </div>
                                </div>
