                                </span>
                                <span 
                                  className={`chat-group-name ${tieneNoLeidos && estaColapsado ? "unread-group" : ""}`}
                                  onClick={() => toggleGrupoGroupCollapse(nombreGrupo)}
                                >
                                  ­ƒôü {nombreGrupo}
