                        })}
                      </div>

                      <div className="chat-input-pro">
                        {respondiendoMensaje && (
                          <div className="chat-reply-bar">
                            <div className="chat-reply-info">
                              <span>Respondiendo a {respondiendoMensaje.usuario}</span>
