                              <span className="cpep-title">Emojis</span>
                              <input
                                className="cpep-search"
                                type="text"
                                placeholder="BuscarÔÇª"
                                value={emojiBusqueda}
                                onChange={(e) => setEmojiBusqueda(e.target.value)}
                              />
                            </div>
                            {/* Pills de categor├¡a */}
