                              if (e.key === "Enter" && !e.shiftKey) {
                              if (manejarEnterLista(e)) return;
                              e.preventDefault();
                              enviarMensaje();
                              } else if (e.key === "Escape") {
                                setMostrarSugerenciasMencion(false);
                              }
                            }}
