                    ) : null}
                    <small className="builder-help-text">Agrega cada opci├│n con el bot├│n y aparecer├í en el desplegable real.</small>
                  </div>
                ) : <div className="component-rule-hint compact-surface-card"><strong>Origen conectado</strong><p>Las opciones del men├║ se llenar├ín autom├íticamente desde {OPTION_SOURCE_TYPES.find((option) => option.value === draft.optionSource)?.label || "otra fuente"}.</p></div>}
                <div className="component-rule-hint compact-surface-card"><strong>Desplegable real</strong><p>Este componente s├¡ muestra un men├║ dentro de cada fila del tablero.</p></div>
              </section>
            ) : null}

            {showInventoryProperty ? (
              inventorySourceFields.length ? (
                <section className="component-studio-section three-columns component-studio-short-grid">
                  <label className="app-modal-field">
                    <span>Campo origen</span>
                    <select value={resolvedInventorySourceFieldId} onChange={(event) => onChange((current) => ({ ...current, sourceFieldId: event.target.value }))}>
                      {inventorySourceFields.map((column) => <option key={column.id} value={column.id}>{formatInventorySourceFieldLabel(column)}</option>)}
                    </select>
                    <small className="builder-help-text">Elige el buscador de inventario del que se tomar├í la informaci├│n.</small>
                  </label>
                  <label className="app-modal-field">
                    <span>Dato de inventario</span>
                    <select value={draft.inventoryProperty} onChange={(event) => onChange((current) => ({ ...current, inventoryProperty: event.target.value }))}>
                      {INVENTORY_PROPERTIES.map((property) => <option key={property.value} value={property.value}>{property.label}</option>)}
                    </select>
                    <small className="builder-help-text">Trae autom├íticamente c├│digo, nombre, presentaci├│n o conversiones.</small>
                  </label>
                  <div className="component-rule-hint compact-surface-card">
                    <strong>Enlace autom├ítico</strong>
                    <p>{selectedInventorySourceField ? `Quedar├í ligado a ${formatInventorySourceFieldLabel(selectedInventorySourceField)} y puedes cambiarlo aqu├¡ cuando lo necesites.` : "Se ligar├í en autom├ítico al ├║ltimo buscador de inventario disponible."}</p>
                  </div>
                </section>
              ) : (
                <section className="component-studio-section component-studio-empty">
