const TARIMA_PAUSE_START_HOUR = (() => {
  const raw = Number.parseInt(String(import.meta.env?.VITE_TARIMA_PAUSE_START_HOUR ?? "16"), 10);
  if (!Number.isFinite(raw)) return 16;
