    return children;
  } catch (e) {
    if (!err) setErr(e);
    return <div style={{color:'#b91c1c',background:'#fff0f0',padding:24,borderRadius:16}}><b>Error en ReturnsReconditionScanner:</b><br/>{String(e.message || e)}</div>;
  }
}

