        </div>
      ) : null}

      <div className="returns-scan-head">
        <div>
          <h4>{viewingClosedTarima ? "Vista tarima cerrada" : "Modo escaneo"} ┬À {displayedTarima ? `Tarima ${displayedTarima.tarimaNumber}` : "Inicio escaneo"}</h4>
          <p>{displayedTarima ? `Flujo: ${displayedTarima.flowType === "reacondicionado" ? "Reacondicionado" : "Devoluci├│n"}` : "Escanea un c├│digo para crear tarima"}</p>
        </div>
        <div className="saved-board-list">
          {manualGlobalPause ? (
            <span className="chip" style={{ background: "#fee2e2", color: "#991b1b" }}>
              ÔÅ© Pausa global activa
            </span>
          ) : null}
          {!manualGlobalPause && systemPaused && (
            <span
              className="chip"
              style={{ background: "#fee2e2", color: "#991b1b" }}
              title={`Horario activo: ${TARIMA_PAUSE_WINDOW_LABEL} ┬À ${TARIMA_PAUSE_TIMEZONE}`}
            >
