            return completedProducts.length > 0 ? (
              <div style={{ borderBottom: "1px solid rgba(15, 77, 64, 0.2)", paddingBottom: "0.8rem", marginBottom: "0.8rem", display: "flex", gap: "0.5rem", flexWrap: "wrap" }}>
