                      type="button"
                      onClick={() => toggleProductCollapsed(productKey)}
                      style={{
                        padding: "0.5rem 1rem",
                        background: isCollapsed ? "#f0fdf4" : "#e8f5e9",
                        border: "1px solid #4caf50",
