          </label>
          {pendingItem ? (
            <>
              <label className="app-modal-field" style={{ gridColumn: "1 / -1" }}>
                <span>Lotes guardados</span>
                <select
                  value={boxForm.selectedLotKey || ""}
                  onChange={(event) => {
