              </label>
              <label className="app-modal-field">
                <span>Caducidad</span>
                <input
                  value={boxForm.expiry}
                  onChange={(event) => setBoxForm((current) => ({ ...current, selectedLotKey: "", expiry: normalizeExpiryInput(event.target.value) }))}
