                  style={{ textTransform: "uppercase" }}
                />
              </label>
              <label className="app-modal-field">
                <span>Etiqueta</span>
                <input
                  value={boxForm.etiqueta}
                  onChange={(event) => setBoxForm((current) => ({ ...current, selectedLotKey: "", etiqueta: event.target.value }))}
