      </Modal>

      <Modal
        open={tarimaPauseState.open}
        title="Pausar tarima"
        confirmLabel="Confirmar pausa"
        cancelLabel="Cancelar"
        onClose={() => {
          setTarimaPauseState({ open: false, reason: "", error: "" });
        }}
        onConfirm={handleConfirmTarimaPause}
      >
        <div className="returns-scan-modal-grid">
          <label className="app-modal-field">
            <span>Motivo de pausa</span>
            <input value={tarimaPauseState.reason} onChange={(event) => setTarimaPauseState((current) => ({ ...current, reason: event.target.value, error: "" }))} placeholder="Describe por qu├® se detiene la tarima" />
          </label>
          {tarimaPauseState.error ? <p className="validation-text">{tarimaPauseState.error}</p> : null}
          <p className="modal-footnote">El motivo es obligatorio para poder pausar.</p>
        </div>
      </Modal>

      <Modal
        open={pausedReminderOpen && tarimaStatus === TARIMA_STATUS_PAUSED}
        title="Workflow de tarima en pausa"
        confirmLabel="Entendido"
        hideCancel
        onClose={() => setPausedReminderOpen(false)}
        onConfirm={() => setPausedReminderOpen(false)}
      >
        <div className="returns-scan-modal-grid">
          <p className="modal-footnote">
            La tarima permanece en pausa hasta que un Lead o el creador del tablero la reanude desde el workflow general superior.
          </p>
          {activeTarima?.lastPauseReason ? (
            <p className="validation-text">Motivo registrado: {activeTarima.lastPauseReason}</p>
          ) : null}
        </div>
      </Modal>

      <Modal
        open={lotModalOpen}
        title={`Registrar lote ┬À ${pendingItem?.code || ""}`}
        confirmLabel="Guardar lote"
        cancelLabel="Cancelar"
        onClose={() => { setLotModalOpen(false); setPendingItem(null); }}
        onConfirm={registerScannedItemLot}
      >
        <div className="saved-board-list" style={{ marginBottom: "0.5rem" }}>
          <span className="chip">Escanea mismo c├│digo para +1 autom├ítico</span>
          <span className="chip">C├│digo activo: {pendingItem?.code || "-"}</span>
        </div>
        <div className="returns-scan-modal-grid">
          <label className="app-modal-field">
            <span>Lotes guardados</span>
            <select
              value={lotForm.selectedLotKey}
              onChange={(event) => {
                const selectedKey = String(event.target.value || "");
                if (selectedKey === "__new__") {
                  setLotForm((current) => ({ ...current, selectedLotKey: "", lot: "", expiry: "", etiqueta: "" }));
                  return;
                }
                const selected = pendingLotOptions.find((entry) => entry.key === selectedKey);
                if (!selected) {
                  setLotForm((current) => ({ ...current, selectedLotKey: "" }));
                  return;
                }
                setLotForm((current) => ({
                  ...current,
                  selectedLotKey: selected.key,
                  lot: selected.lot,
                  expiry: selected.expiry,
                  etiqueta: selected.etiqueta || "",
                }));
              }}
            >
              <option value="">Selecciona un lote guardado</option>
              {pendingLotOptions.map((entry) => (
                <option key={entry.key} value={entry.key}>{entry.label}</option>
              ))}
              <option value="__new__">Nuevo lote...</option>
            </select>
          </label>
          <label className="app-modal-field">
            <span>Lote</span>
            <input
              ref={lotInputRef}
              value={lotForm.lot}
              onChange={(event) => setLotForm((current) => ({ ...current, selectedLotKey: "", lot: event.target.value }))}
              onKeyDown={(event) => {
                if (event.key !== "Enter") return;
                event.preventDefault();
                void handleModalLotSubmit();
              }}
              placeholder="Ej: L2304A"
            />
          </label>
          <label className="app-modal-field">
            <span>Caducidad</span>
            <input
              ref={expiryInputRef}
              value={lotForm.expiry}
              onChange={(event) => setLotForm((current) => ({ ...current, selectedLotKey: "", expiry: normalizeExpiryInput(event.target.value) }))}
              placeholder="Ej: AGO-2026"
              style={{ textTransform: "uppercase" }}
            />
          </label>
          <label className="app-modal-field">
            <span>Etiqueta</span>
            <input
              value={lotForm.etiqueta}
              onChange={(event) => setLotForm((current) => ({ ...current, selectedLotKey: "", etiqueta: event.target.value }))}
              placeholder="Ej: ETQ-001"
            />
          </label>
          <label className="app-modal-field">
            <span>Piezas</span>
            <input
              type="number"
              min="1"
              value={lotForm.pieces}
              onChange={(event) => {
                const rawValue = event.target.value;
                setLotForm((current) => ({
                  ...current,
                  pieces: rawValue === "" ? "" : Number(rawValue),
                }));
              }}
            />
          </label>
        </div>
        {pendingItem ? (
          <div className="returns-scan-history">
            <strong>Lotes recientes guardados para este producto</strong>
            <div className="saved-board-list">
              {getItemLotHistory(pendingItem).length ? getItemLotHistory(pendingItem).slice(0, 8).map((entry) => (
                <button
                  key={`${entry.lot}-${entry.expiry}-${entry.etiqueta || ""}`}
                  type="button"
                  className="chip"
                  onClick={() => setLotForm((current) => ({ ...current, lot: entry.lot, expiry: normalizeExpiryInput(entry.expiry), etiqueta: String(entry?.etiqueta || "") }))}
                >
                  {entry.lot} ┬À {entry.expiry}{entry?.etiqueta ? ` ┬À ${entry.etiqueta}` : ""}
                </button>
              )) : <span className="chip">Sin historial todav├¡a</span>}
            </div>
          </div>
        ) : null}
      </Modal>

    </section>
  );
}

import { useEffect, useMemo, useState } from "react";
import { BarChart3, Check, Plus, Save, Trash2, Upload, X } from "lucide-react";
import { uploadFileToCloudinary } from "../services/upload.service";

function emptyTemplateDraft() {
  return {
    id: "",
    area: "",
    process: "",
    questions: [
      { id: crypto.randomUUID(), type: "yesno", text: "", required: true, placeholder: "" },
    ],
  };
}

function formatDateTime(value) {
  if (!value) return "Sin fecha";
  return new Intl.DateTimeFormat("es-MX", { dateStyle: "medium", timeStyle: "short" }).format(new Date(value));
}

function getAuditDurationSeconds(audit) {
  const startMs = Date.parse(audit?.startedAt || "");
  const endMs = Date.parse((audit?.status === "closed" ? audit?.closedAt : audit?.updatedAt) || "");
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs) || endMs < startMs) return 0;
  return Math.round((endMs - startMs) / 1000);
}

function formatDuration(seconds) {
  const safe = Math.max(0, Number(seconds || 0));
  const hours = Math.floor(safe / 3600);
  const minutes = Math.floor((safe % 3600) / 60);
  if (hours > 0) return `${hours}h ${minutes}m`;
  return `${minutes}m`;
}

export default function AuditoriasProcesos({ contexto }) {
  const {
    rootAreaOptions,
    processAuditTemplates,
    processAudits,
    actionPermissions,
    currentUser,
    upsertProcessAuditTemplate,
    deleteProcessAuditTemplate,
    createProcessAudit,
    updateProcessAudit,
    addProcessAuditEvidence,
    removeProcessAuditEvidence,
    pushAppToast,
  } = contexto;

  const canManageAudits = Boolean(actionPermissions?.manageProcessAudits);
  const canManageTemplates = Boolean(actionPermissions?.manageProcessAuditTemplates);

  const [activeTab, setActiveTab] = useState("capture");
  const [templateDraft, setTemplateDraft] = useState(() => emptyTemplateDraft());
  const [newAuditArea, setNewAuditArea] = useState("");
  const [newAuditProcess, setNewAuditProcess] = useState("");
  const [newAuditTemplateId, setNewAuditTemplateId] = useState("");
  const [selectedAuditId, setSelectedAuditId] = useState("");
  const [auditDraft, setAuditDraft] = useState(null);
  const [isAuditDirty, setIsAuditDirty] = useState(false);
  const [uploadingEvidence, setUploadingEvidence] = useState(false);

  const areaOptions = useMemo(() => {
    const fromCatalog = Array.isArray(rootAreaOptions) ? rootAreaOptions : [];
    const fromTemplates = (processAuditTemplates || []).map((item) => item.area);
    const merged = Array.from(new Set([...fromCatalog, ...fromTemplates].filter(Boolean)));
    return merged.sort((a, b) => a.localeCompare(b, "es-MX"));
  }, [processAuditTemplates, rootAreaOptions]);

  const processOptionsForArea = useMemo(() => {
    const byArea = new Map();
    (processAuditTemplates || []).forEach((item) => {
      const area = String(item.area || "").trim();
      const process = String(item.process || "").trim();
      if (!area || !process) return;
      if (!byArea.has(area)) byArea.set(area, new Set());
      byArea.get(area).add(process);
    });

    return Object.fromEntries(Array.from(byArea.entries()).map(([area, values]) => [area, Array.from(values).sort((a, b) => a.localeCompare(b, "es-MX"))]));
  }, [processAuditTemplates]);

  const templateCandidates = useMemo(() => {
    if (!newAuditArea) return [];
    return (processAuditTemplates || []).filter((entry) => entry.area === newAuditArea && (!newAuditProcess || entry.process === newAuditProcess));
  }, [newAuditArea, newAuditProcess, processAuditTemplates]);

  const sortedAudits = useMemo(
    () => [...(processAudits || [])].sort((left, right) => Date.parse(right.startedAt || right.updatedAt || "") - Date.parse(left.startedAt || left.updatedAt || "")),
    [processAudits],
  );

  const selectedAudit = useMemo(
    () => sortedAudits.find((entry) => entry.id === selectedAuditId) || sortedAudits[0] || null,
    [selectedAuditId, sortedAudits],
  );

  useEffect(() => {
    if (!selectedAudit) {
      setAuditDraft(null);
      setSelectedAuditId("");
      return;
    }

    setSelectedAuditId(selectedAudit.id);
    setAuditDraft({
      ...selectedAudit,
      questions: (selectedAudit.questions || []).map((question) => ({ ...question })),
      evidences: [...(selectedAudit.evidences || [])],
    });
    setIsAuditDirty(false);
  }, [selectedAudit?.id]);

  useEffect(() => {
    if (!auditDraft || !isAuditDirty || !canManageAudits) return undefined;

    const timer = setTimeout(async () => {
      try {
        await updateProcessAudit(auditDraft.id, {
          area: auditDraft.area,
          process: auditDraft.process,
          notes: auditDraft.notes || "",
          status: auditDraft.status,
          questions: (auditDraft.questions || []).map((question) => ({
            id: question.id,
            type: question.type,
            text: question.text,
            required: question.required,
            placeholder: question.placeholder,
            answer: question.answer,
          })),
        });
        setIsAuditDirty(false);
      } catch {
        // El usuario todav├¡a puede guardar de forma manual; evita ruido en cada tecleo.
      }
    }, 700);

    return () => clearTimeout(timer);
  }, [auditDraft, canManageAudits, isAuditDirty, updateProcessAudit]);

  const dashboardStats = useMemo(() => {
    const total = sortedAudits.length;
    const closed = sortedAudits.filter((entry) => entry.status === "closed").length;
    const open = total - closed;
    const totalDuration = sortedAudits.reduce((sum, entry) => sum + getAuditDurationSeconds(entry), 0);
    const avgDuration = total > 0 ? Math.round(totalDuration / total) : 0;

    const byAreaMap = new Map();
    sortedAudits.forEach((entry) => {
      const area = entry.area || "Sin ├írea";
      byAreaMap.set(area, (byAreaMap.get(area) || 0) + 1);
    });

    const byArea = Array.from(byAreaMap.entries())
      .map(([label, value]) => ({ label, value }))
      .sort((left, right) => right.value - left.value);

    return { total, closed, open, avgDuration, byArea };
  }, [sortedAudits]);

  async function handleSaveTemplate() {
    if (!canManageTemplates) return;

    const normalizedQuestions = (templateDraft.questions || [])
      .map((question) => ({
        ...question,
        text: String(question.text || "").trim(),
        placeholder: String(question.placeholder || "").trim(),
      }))
      .filter((question) => question.text);

    if (!templateDraft.area.trim() || !templateDraft.process.trim() || !normalizedQuestions.length) {
      pushAppToast("Completa ├írea, proceso y al menos una pregunta para guardar la plantilla.", "warning");
      return;
    }

    try {
      await upsertProcessAuditTemplate({
        id: templateDraft.id || undefined,
        area: templateDraft.area.trim(),
        process: templateDraft.process.trim(),
        questions: normalizedQuestions,
      });
      setTemplateDraft(emptyTemplateDraft());
      pushAppToast("Plantilla guardada correctamente.", "success");
    } catch (error) {
      pushAppToast(error?.message || "No se pudo guardar la plantilla.", "danger");
    }
  }

  async function handleCreateAudit() {
    if (!canManageAudits) return;
    if (!newAuditArea.trim() || !newAuditProcess.trim()) {
      pushAppToast("Selecciona ├írea y proceso para crear la auditor├¡a.", "warning");
      return;
    }

    const template = (processAuditTemplates || []).find((entry) => entry.id === newAuditTemplateId) || null;

    try {
      const createdAuditId = await createProcessAudit({
        area: newAuditArea.trim(),
        process: newAuditProcess.trim(),
        templateId: template?.id || null,
        questions: template ? undefined : [{ type: "yesno", text: "┬┐Cumple con el est├índar definido?", required: true }],
      });
      if (createdAuditId) setSelectedAuditId(createdAuditId);
      pushAppToast("Auditor├¡a creada.", "success");
    } catch (error) {
      pushAppToast(error?.message || "No se pudo crear la auditor├¡a.", "danger");
    }
  }

  async function handleCloseAudit() {
    if (!canManageAudits || !auditDraft) return;
    try {
      await updateProcessAudit(auditDraft.id, {
        status: "closed",
        notes: auditDraft.notes || "",
        questions: auditDraft.questions || [],
      });
      pushAppToast("Auditor├¡a cerrada correctamente.", "success");
    } catch (error) {
      pushAppToast(error?.message || "No se pudo cerrar la auditor├¡a.", "danger");
    }
  }

  async function handleUploadEvidence(event) {
    const file = event.target.files?.[0];
    if (!file || !auditDraft || !canManageAudits) return;
    setUploadingEvidence(true);

    try {
      const uploaded = await uploadFileToCloudinary(file);
      await addProcessAuditEvidence(auditDraft.id, {
        url: uploaded.url,
        thumbnailUrl: uploaded.thumbnailUrl,
        name: uploaded.originalName || file.name,
        mimeType: uploaded.fileMimeType || file.type,
      });
      pushAppToast("Evidencia agregada.", "success");
    } catch (error) {
      pushAppToast(error?.message || "No se pudo subir la evidencia.", "danger");
    } finally {
      setUploadingEvidence(false);
      event.target.value = "";
    }
  }

  return (
    <section className="page-grid">
      <article className="surface-card full-width table-card">
        <div className="tab-strip">
          <button type="button" className={activeTab === "capture" ? "tab active" : "tab"} onClick={() => setActiveTab("capture")}>Captura</button>
          <button type="button" className={activeTab === "history" ? "tab active" : "tab"} onClick={() => setActiveTab("history")}>Historial</button>
          <button type="button" className={activeTab === "dashboard" ? "tab active" : "tab"} onClick={() => setActiveTab("dashboard")}>Dashboard</button>
        </div>
      </article>

      {activeTab === "capture" ? (
        <>
          <article className="surface-card table-card">
            <div className="card-header-row">
              <div>
                <h3>Crear auditor├¡a de proceso</h3>
                <p>Selecciona ├írea, proceso y plantilla para iniciar una nueva auditor├¡a.</p>
              </div>
            </div>
            <div className="modal-form-grid">
              <label className="app-modal-field">
                <span>├ürea</span>
                <select value={newAuditArea} onChange={(event) => { setNewAuditArea(event.target.value); setNewAuditProcess(""); setNewAuditTemplateId(""); }}>
                  <option value="">Selecciona ├írea</option>
                  {areaOptions.map((area) => <option key={area} value={area}>{area}</option>)}
                </select>
              </label>
              <label className="app-modal-field">
                <span>Proceso</span>
                <input
                  list="audit-process-options"
                  value={newAuditProcess}
                  onChange={(event) => { setNewAuditProcess(event.target.value); setNewAuditTemplateId(""); }}
                  placeholder="Ej: Recepci├│n"
                />
                <datalist id="audit-process-options">
                  {(processOptionsForArea[newAuditArea] || []).map((process) => <option key={process} value={process} />)}
                </datalist>
              </label>
              <label className="app-modal-field">
                <span>Plantilla</span>
                <select value={newAuditTemplateId} onChange={(event) => setNewAuditTemplateId(event.target.value)}>
                  <option value="">Sin plantilla (manual)</option>
                  {templateCandidates.map((template) => <option key={template.id} value={template.id}>{template.process} ┬À {template.questions?.length || 0} preguntas</option>)}
                </select>
              </label>
              <div className="saved-board-list board-builder-launch-list">
                <button type="button" className="primary-button" onClick={handleCreateAudit} disabled={!canManageAudits}><Plus size={16} /> Iniciar auditor├¡a</button>
              </div>
            </div>
          </article>

          <article className="surface-card table-card">
            <div className="card-header-row">
              <div>
                <h3>Plantillas por proceso</h3>
                <p>Puedes crear, mejorar o eliminar preguntas seg├║n el proceso auditado.</p>
              </div>
            </div>
            <div className="modal-form-grid">
              <label className="app-modal-field">
                <span>├ürea</span>
                <input value={templateDraft.area} onChange={(event) => setTemplateDraft((current) => ({ ...current, area: event.target.value }))} placeholder="Ej: Inventario" />
              </label>
              <label className="app-modal-field">
                <span>Proceso</span>
                <input value={templateDraft.process} onChange={(event) => setTemplateDraft((current) => ({ ...current, process: event.target.value }))} placeholder="Ej: Acomodo" />
              </label>
              {(templateDraft.questions || []).map((question, index) => (
                <article key={question.id} className="surface-card">
                  <div className="card-header-row">
                    <strong>Pregunta {index + 1}</strong>
                    <button
                      type="button"
                      className="icon-button danger"
                      onClick={() => setTemplateDraft((current) => ({ ...current, questions: current.questions.filter((item) => item.id !== question.id) }))}
                      disabled={!canManageTemplates || templateDraft.questions.length <= 1}
                    >
                      <Trash2 size={15} />
                    </button>
                  </div>
                  <div className="modal-form-grid">
                    <label className="app-modal-field">
                      <span>Tipo</span>
                      <select
                        value={question.type}
                        onChange={(event) => setTemplateDraft((current) => ({
                          ...current,
                          questions: current.questions.map((item) => (item.id === question.id ? { ...item, type: event.target.value === "text" ? "text" : "yesno" } : item)),
                        }))}
                      >
                        <option value="yesno">S├¡ / No</option>
                        <option value="text">Texto</option>
                      </select>
                    </label>
                    <label className="app-modal-field">
                      <span>Pregunta</span>
                      <input
                        value={question.text}
                        onChange={(event) => setTemplateDraft((current) => ({
                          ...current,
