                      </div>
                      <div style={{ display: "flex", gap: "0.45rem", flexWrap: "wrap", justifyContent: "flex-end" }}>
                        <span className="chip">{monthEntry.weeks.length} semanas</span>
                        <span className="chip primary">{isOpen ? "Ocultar" : "Ver mes"}</span>
