                                        </thead>
                                        <tbody>
                                          {dayEntry.activities.map((activity) => (
                                            <tr key={activity.id}>
                                              <td>{activity.areaRoot}</td>
                                              <td>{activity.boardName || "General"}</td>
                                              <td>{resolveHistoryActivityLabel(activity)}</td>
