                                        </tbody>
                                      </table>
                                    </div>
                                  ) : (
                                    <span className="subtle-line">No hay actividades registradas para este d├¡a.</span>
                                  )
                                ) : null}
                              </article>
                            );
                          })}
                        </div>
                      </>
                    ) : null}
                  </article>
                );
              })}
            </div>

            {!useBoardHistoryFallback && actionPermissions.deleteWeek && effectiveHistoryWeek ? (
              <div style={{ display: "flex", justifyContent: "flex-end" }}>
                <button
                  type="button"
                  className="icon-button danger"
                  onClick={() => setDeleteWeekModal({ open: true, weekId: effectiveHistoryWeek.id, weekName: effectiveHistoryWeek.name, isSubmitting: false })}
                >
                  <Trash2 size={15} /> Borrar semana
                </button>
              </div>
            ) : null}
          </>
        ) : (
          <article className="surface-card" style={{ padding: "1rem 1.2rem" }}>
            <span className="subtle-line">Selecciona una semana para ver el historial.</span>
          </article>
        )}
      </article>

      {deleteWeekModal.open ? createPortal(
        <div role="dialog" aria-modal="true" aria-labelledby="delete-week-title" style={{ position: "fixed", inset: 0, zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(0,0,0,0.45)", padding: "1rem" }}>
          <div style={{ background: "#fff", borderRadius: "1.25rem", padding: "1.5rem", maxWidth: 460, width: "100%", boxShadow: "0 8px 32px rgba(0,0,0,0.2)" }}>
            <h3 id="delete-week-title" style={{ margin: "0 0 0.5rem", fontSize: "1.1rem", color: "#032121" }}>┬┐Borrar semana completa?</h3>
            <p style={{ margin: "0 0 1.2rem", color: "#555", fontSize: "0.92rem", lineHeight: 1.5 }}>
              Se eliminar├í {deleteWeekModal.weekName || "esta semana"} junto con todas sus actividades y pausas asociadas.
            </p>
            <div style={{ display: "flex", gap: "0.75rem", justifyContent: "flex-end" }}>
              <button
                type="button"
                style={{ padding: "0.5rem 1rem", borderRadius: "0.75rem", border: "1px solid #ddd", background: "#f3f4f6", cursor: "pointer" }}
                onClick={() => setDeleteWeekModal({ open: false, weekId: "", weekName: "", isSubmitting: false })}
                disabled={deleteWeekModal.isSubmitting}
              >
                Cancelar
              </button>
              <button
                type="button"
                style={{ padding: "0.5rem 1rem", borderRadius: "0.75rem", border: "none", background: "#7f1d1d", color: "#fff", cursor: "pointer" }}
                onClick={() => { void confirmDeleteWeek(); }}
                disabled={deleteWeekModal.isSubmitting}
              >
                {deleteWeekModal.isSubmitting ? "Borrando..." : "S├¡, borrar"}
              </button>
            </div>
          </div>
        </div>,
        document.body,
      ) : null}
    </section>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";
import ReturnsReconditionScanner from "../features/boards/ReturnsReconditionScanner.jsx";
import { BoardEditableInventoryPropertyInput, BoardEvidenceCell, BoardMultiSelectDetailCell } from "../components/BoardRuntimeFieldCells.jsx";
import {
  formatBoardRowAssigneeLabel,
  getLivePauseOverflowSeconds,
  getBoardRowResponsibleIds,
  getOperationalElapsedSeconds,
  normalizeSystemOperationalSettings,
  parseBoardWeekKey,
  addDays,
  resolveInventoryPropertySourceFieldId,
} from "../utils/utilidades.jsx";

const EDITABLE_INVENTORY_PROPERTIES = new Set(["lot", "expiry", "label"]);

function parseInventoryLotHistory(rawValue) {
  if (!rawValue) return [];
  if (Array.isArray(rawValue)) return rawValue;
  if (typeof rawValue !== "string") return [];
  try {
    const parsed = JSON.parse(rawValue);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function getInventoryPropertySuggestions(item, property, fallbackValue = "") {
  const customFields = item?.customFields && typeof item.customFields === "object" ? item.customFields : {};
  const lotHistory = parseInventoryLotHistory(customFields.lotesCaducidades);
  const values = [];
  if (property === "lot") {
    values.push(customFields.lote);
    lotHistory.forEach((entry) => values.push(entry?.lot));
  } else if (property === "expiry") {
    values.push(customFields.caducidad);
    lotHistory.forEach((entry) => values.push(entry?.expiry));
  } else if (property === "label") {
    values.push(customFields.etiqueta);
    lotHistory.forEach((entry) => values.push(entry?.etiqueta || entry?.label));
  }

  if (fallbackValue) values.push(fallbackValue);

  const seen = new Set();
  return values
    .map((entry) => String(entry || "").trim())
    .filter((entry) => {
      if (!entry) return false;
      const key = entry.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
}

export default function MisTableros({ contexto }) {
  const {
    visibleControlBoards: _visibleControlBoards,
    customBoardSearch: _customBoardSearch,
    setCustomBoardSearch: _setCustomBoardSearch,
    selectedCustomBoard,
    filteredVisibleControlBoards,
