      pdf.text(`Pausa: ${formatMetricNumber(dashboardMetrics.pauseHours, 2)} h ┬À ${dashboardMetrics.pauseCount} interrupciones`, marginX + halfW + 20, timeY + 92);

      drawSectionTable("Top de pausas ÔÇö Causas de tiempo perdido", ["Motivo de pausa", "Eventos", "Minutos perdidos", "% del tiempo en pausa", "Clasificaci├│n"], pauseAnalysis.map((item) => [
